import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Perform validation and ensure buffer size is sufficient
        int maxLength = 10; // Maximum allowed length for input
        if (name.length() > maxLength) {
            System.out.println("Input exceeds maximum allowed length.");
            return;
        }

        byte[] buffer = new byte[maxLength];
        System.arraycopy(name.getBytes(), 0, buffer, 0, Math.min(name.length(), maxLength));

        System.out.println("Hello, " + new String(buffer).trim());
    }
}

### Explanation:
취약유형: Buffer Overflow
